25	  });
26	
27	  it('initDb creates the comments table', () => {
28	    initDb(':memory:');
29	    const result = getDb().prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='comments'").get();
30	    assert.equal(result.name, 'comments');
31	    closeDb();
32	  });
33	
34	  it('initDb enables foreign keys', () => {
35	    initDb(':memory:');
