Design a TDD implementation plan for adding a comments REST API route to an Express.js server. Here's everything you need to know:

## Project Context
This is a Kanban board app with an Express backend. The task is to create `server/api/comments.js` with a POST endpoint for creating comments on cards, then mount it in `server/index.js`.

## Existing Codebase

### server/index.js (current state):
```javascript
import express from 'express';
import cors from 'cors';
import { fileURLToPath } from 'node:url';
import { resolve, dirname, join } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));

function createApp() {
  const app = express();
  const isProduction = process.env.NODE_ENV === 'production';

  app.use(cors({ origin: isProduction ? false : true, credentials: true }));
  app.use(express.json());

  app.get('/health', (_req, res) => res.json({ ok: true }));

  if (!isProduction) {
    app.post('/dev/echo', (req, res) => res.json(req.body));
    app.get('/dev/error', (req, res, next) => {
      const err = new Error('Test error');
      err.status = req.query.status ? parseInt(req.query.status, 10) : 500;
      next(err);
    });
  }

  if (isProduction) {
    const distPath = join(__dirname, '..', 'client', 'dist');
    app.use(express.static(distPath));
    app.get('*', (_req, res) => res.sendFile(join(distPath, 'index.html')));
  }

  app.use((_req, res) => res.status(404).json({ error: 'Not Found' }));
  app.use((err, _req, res, _next) => {
    const status = err.status || err.statusCode || 500;
    res.status(status).json({ error: err.message || 'Internal Server Error' });
  });

  return app;
}

if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  const app = createApp();
  const PORT = process.env.PORT || 3001;
  app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
}

export { createApp };
```

